import React from "react";
import { TrendingUp, TrendingDown, Star } from "lucide-react";

const CompanyItem = ({ company, isActive, onClick }) => {
  // Numeric fields ko number me convert karo, fallback 0
  const currentPrice = Number(company.current_price ?? 0);
  const change = Number(company.change ?? 0);
  const changePercent = Number(company.change_percent ?? 0);
  const pe = Number(company.pe ?? 0);
  const volume = company.volume ?? "0";

  const isPositive = change >= 0;

  return (
    <div
      className={`group p-4 mx-2 my-1 rounded-2xl cursor-pointer transition-all duration-500 ease-out transform hover:-translate-y-1 ${
        isActive
          ? "bg-gradient-to-br from-blue-600 via-blue-500 to-indigo-600 text-white shadow-2xl scale-[1.02]"
          : "bg-white hover:bg-gray-50 hover:shadow-xl border border-gray-100"
      }`}
      onClick={onClick}
    >
      {/* Header */}
      <div className="flex items-start justify-between mb-3">
        <div className="flex-1 min-w-0">
          <h3
            className={`font-bold text-sm leading-tight mb-1 ${
              isActive ? "text-white" : "text-gray-900"
            }`}
          >
            {company.name || "Unknown Name"}
          </h3>
          <div className="flex items-center gap-2">
            <span
              className={`text-xs font-medium px-2 py-1 rounded-full ${
                isActive ? "bg-white/20 text-blue-100" : "bg-gray-100 text-gray-600"
              }`}
            >
              {company.symbol || "N/A"}
            </span>
            <span
              className={`text-xs ${isActive ? "text-blue-200" : "text-gray-500"}`}
            >
              {company.sector || "N/A"}
            </span>
          </div>
        </div>
        {isActive && <Star className="w-4 h-4 text-yellow-300 fill-current" />}
      </div>

      {/* Price */}
      <div className="space-y-2">
        <div className="flex items-end justify-between">
          <span
            className={`text-lg font-bold ${isActive ? "text-white" : "text-gray-900"}`}
          >
            ₹{currentPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}
          </span>
          <div
            className={`flex items-center gap-1 px-2 py-1 rounded-lg text-xs font-medium ${
              isActive
                ? isPositive
                  ? "bg-green-500/30 text-green-100"
                  : "bg-red-500/30 text-red-100"
                : isPositive
                ? "bg-green-50 text-green-700"
                : "bg-red-50 text-red-700"
            }`}
          >
            {isPositive ? <TrendingUp size={12} /> : <TrendingDown size={12} />}
            {isPositive ? "+" : ""}
            {changePercent.toFixed(2)}%
          </div>
        </div>

        {/* Extra Info */}
        <div
          className={`flex justify-between text-xs ${
            isActive ? "text-blue-100" : "text-gray-500"
          }`}
        >
          <span>Vol: {Number(volume).toLocaleString()}</span>
          <span>P/E: {pe.toFixed(2)}</span>
        </div>
      </div>
    </div>
  );
};

export default CompanyItem;
